import React, { Fragment, useState, useEffect } from 'react';
import { Col, Card, CardHeader, CardBody, Media, Label, Input, Form, Row } from 'reactstrap';
import SweetAlert from 'sweetalert2';
import DataTable from 'react-data-table-component';
import { H3, Btn, Breadcrumbs, H4 } from '../../../AbstractElements';
import { Link, useNavigate } from 'react-router-dom';
import { getClientUrlDataToken, postClientUrlWithToken } from '../../../Utils/restUtils';
import { Add, CasProvider, CasProviderList, Search, Filter } from '../../../Constant';
import { useSelector } from 'react-redux';
import { deleteProvider, deleteProviderRole, statusProvider, statusProviderRole, viewProvider, viewProviderRole } from '../../../CommonUrl';
import { toast } from 'react-toastify';
import { ProviderColumns } from '../../../Data/MockTable/SettingsTableHeader';
import Transparentspinner from '../../Common/Loader/Transparentspinner';

const ProviderContainer = () => {
    const style2 = { width: 60, fontSize: 13, padding: 3, marginRight: '10px' };
    const authState = useSelector((state) => state.auth);
    const [providerList, setProviderList] = useState([]);
    const [searchKeyword, setSearchKeyword] = useState('');
    const [loading, setLoading] = useState(false);
    const [resetPaginationToggle, setResetPaginationToggle] = useState(false);
    const navigate = useNavigate();
    const [totalRows, setTotalRows] = useState(0);
    const [perPage, setPerPage] = useState(10);
    const [currentPage, setCurrentPage] = useState(1);

    useEffect(() => {
        if (searchKeyword == '') {
            setLoading(true);
            providerData();
        }
    }, [searchKeyword]);

    const handleSearchInputChange = (event) => {
        setSearchKeyword(event.target.value);
    };

    const handleFilterSubmit = (event) => {
        event.preventDefault();
        setLoading(true);
        providerData();
    };


    const handleSwitchToggle = async (event, itemId) => {
        const checked = event.target.checked;
        let reqSwitch = null;
        if (checked === true) {
            reqSwitch = { provider_id: itemId, status: 'inactive' }
        } else {
            reqSwitch = { provider_id: itemId, status: 'active' }
        }
        const statusChange = await postClientUrlWithToken(authState.apiUrl, authState.userRole === 1 ? statusProvider : statusProviderRole, reqSwitch);
        if (statusChange.data.status === true) {
            toast.success(statusChange.data.message);
        } else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
    }

    const redirectToEditForm = (data) => {
        const editFormURL = `${process.env.PUBLIC_URL}/settings/provider-edit?id=${data.id}`;
        navigate(editFormURL);
    };

    const deleteProviderList = (userId) => {
        SweetAlert.fire({
            title: 'Confirm deletion?',
            text: 'This action cannot be undone.',
            icon: 'warning',
            showCancelButton: true,
            confirmButtonText: 'Ok',
            cancelButtonText: 'cancel',
            reverseButtons: true
        }).then(async (result) => {
            setLoading(true);
            if (result.value) {
                const deleteRes = { provider_id: userId }
                let providerDelete = await postClientUrlWithToken(authState.apiUrl, authState.userRole === 1 ? deleteProvider : deleteProviderRole, deleteRes);
                if (providerDelete.status === 200) {
                    // if (providerDelete.data.status === true) {
                    SweetAlert.fire(
                        'Deleted!',
                        'Your file has been deleted.',
                        'success'
                    );
                    providerData();
                    // } else {
                    //     navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
                    // }
                } else if (providerDelete.status >= 400 && providerDelete.status <= 405) {
                    navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
                } else if (providerDelete.status >= 500 && providerDelete.status <= 505) {
                    navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
                } else {
                    navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
                }
            }
            setLoading(false);
        });
    };

    const handlePageChange = page => {
        providerData(page);
        setCurrentPage(page);
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        providerData(page, newPerPage);
        setPerPage(newPerPage);
    };

    const providerData = async (page = currentPage, size = perPage) => {
        setLoading(true);
        let data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? viewProvider + `?search=${searchKeyword}&page=${page}&page_length=${size}` : viewProviderRole + `?search=${searchKeyword}&page=${page}&page_length=${size}`);
        if (data.status === true) {
            setResetPaginationToggle(!resetPaginationToggle);
            if (data.data && Array.isArray(data.data.data)) {
                const SerialNo = (page - 1) * size + 1; // Calculate the starting SI for the current page
                setProviderList(data.data.data.map((e, index) => {
                    return {
                        Si: SerialNo + index,
                        Name: e.name,
                        Description: e.description,
                        Status: <Media body className={`flex-grow-1 text-end icon-state`}>
                            <Label className="switch">
                                <Input type="checkbox"
                                    defaultChecked={e.status === "active" ? true : false}
                                    onChange={(event) => handleSwitchToggle(event, e.id)}
                                />
                                <span className="switch-state" ></span>
                            </Label>
                        </Media>,
                        action:
                            <div>
                                <span>
                                    <Btn attrBtn={{ style: style2, color: 'primary btn-xs', type: 'button', onClick: () => redirectToEditForm(e) }}>Edit </Btn>
                                </span>
                                <span>
                                    <Btn attrBtn={{ style: style2, className: 'me-2', color: 'danger btn-xs', type: 'button', onClick: () => { deleteProviderList(e.id) } }}>Delete</Btn>
                                </span>
                            </div >
                    }
                }))
                setTotalRows(data.data.total);
            }
        } else if (data.status >= 400 && data.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (data.status >= 500 && data.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
        setLoading(false);
    };
    const onSubmit = async (data) => {

    };

    return (
        <Fragment>
            {loading && <Transparentspinner />}
            <Breadcrumbs mainTitle={CasProvider} parent="Settings" title={CasProvider} />
            <Card className='cardWidth'>
                <CardHeader style={{ margin: '-5px 0 -20px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <H3>{CasProviderList}</H3>
                    <div>
                        <Link to={`${process.env.PUBLIC_URL}/settings/provider-add`} className="btn btn-primary">{Add}</Link>
                    </div>
                </CardHeader>
                <CardBody>
                    <span className='custom-span'>
                        <Form className="needs-validation" noValidate onSubmit={handleFilterSubmit}>
                            <Row className="ps-3 mb-4 custom-search-filter align-items-center">
                                <Col xs="6" sm="4" md="2" lg="2">
                                    <input className="form-control  custom-search-input " placeholder={Search} id="validationCustom01" type="text" value={searchKeyword} onChange={handleSearchInputChange}
                                    />
                                </Col>
                                <Col xs="6" sm="6" md="4" lg="3">
                                    <Btn className="custom-filter-btn" attrBtn={{ color: "primary" }} type="submit">{Filter}</Btn>
                                </Col>
                            </Row>
                        </Form>
                    </span>
                    <div className="order-history table-responsive">
                        <DataTable
                            data={providerList}
                            columns={[
                                {
                                    name: <H4>Sl.No</H4>,
                                    selector: (row, index) => row.Si, // Assign SI dynamically based on current index
                                    width: '70px',
                                    center: true,
                                    sortable: false, // Disable sorting for SI
                                },
                                ...ProviderColumns // All other columns remain the same
                            ]}
                            pagination
                            paginationServer
                            defaultSortAsc
                            paginationRowsPerPageOptions={[10, 25, 50, 100]}
                            paginationTotalRows={totalRows}
                            paginationDefaultPage={currentPage}
                            onChangeRowsPerPage={handlePerRowsChange}
                            onChangePage={handlePageChange}
                            style={{ border: '1px solid' }}
                        />
                    </div>
                </CardBody>
            </Card>
        </Fragment>
    );
};
export default ProviderContainer;